public class CSVFormatTest {

    private CSVFormat createCSVFormatWithQuoteCharacter(Character quoteCharacter) throws Exception {
        // Use the withQuote method to create a new CSVFormat instance with the desired quoteCharacter
        return CSVFormat.DEFAULT.withQuote(quoteCharacter);
    }

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        CSVFormat format = createCSVFormatWithQuoteCharacter(null);

        boolean result = format.isQuoteCharacterSet();
        assertFalse(result, "Expected isQuoteCharacterSet() to return false when quoteCharacter is null");
    }

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsNotNull() throws Exception {
        CSVFormat format = createCSVFormatWithQuoteCharacter('"');

        boolean result = format.isQuoteCharacterSet();
        assertTrue(result, "Expected isQuoteCharacterSet() to return true when quoteCharacter is not null");
    }
}
